INSERT INTO `v1_372d63fbd9521d18ff3822bb100fe1cd5cd49a1098718bdd6ad5cbdbedffc78c` VALUES (0.625, "ツムギ・オンステージ！ツムギがキャップのステージでかわいく\nポーズを決めている。どこでも好きな場所に気軽に飾ることが可\n能。", 6, 11601, "ツムギのボトルキャップ", 0.75, 1);
INSERT INTO `v1_372d63fbd9521d18ff3822bb100fe1cd5cd49a1098718bdd6ad5cbdbedffc78c` VALUES (0.625, "サマー衣装のツムギが、キャップでオンステージ！涼しげな衣装を\nまとい、熱いステージを繰り広げた彼女の勇姿を思い出すことがで\nきる。", 6, 11602, "ツムギのサマーボトルキャップ", 0.75, 1);
